SELECT mo.id, mo.eq_id, e.eq_name,
       mo.order_type, mo.priority, mo.status,
       mo.title, mo.assignee, mo.created_at
FROM maint_order mo
JOIN equipment e ON mo.eq_id = e.eq_id


        AND mo.eq_id = #{eqId}


        AND mo.status = #{status}


ORDER BY mo.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM maint_order


        AND eq_id = #{eqId}


        AND status = #{status}

mapper.update:
UPDATE maint_order
SET status = #{status}

        , assignee = #{assignee}


        , action_taken = #{actionTaken}


        , started_at = #{startedAt}


        , completed_at = #{completedAt}

WHERE id = #{id}
